package com.agent.tool.engine.api.impl;  import com.agent.tool.engine.api.SandboxBorrower; import org.slf4j.Logger; import org.slf4j.LoggerFactory; import org.springframework.stereotype.Component;  import java.util.Map; import java.util.concurrent.ConcurrentHashMap; import java.util.concurrent.atomic.AtomicLong;  /**  * F8 R3 沙箱借用 / 回收实现 (container borrow + recycle)。  *  * <p>骨架阶段使用 ConcurrentHashMap 维护借用中的沙箱 ID 集合,  * borrow() 生成新 ID, recycle() 从集合中移除 (模拟 docker rm)。  * 生产实现应替换为 Docker / K8s 容器池。</p>  */ @Component public class SandboxBorrowerImpl implements SandboxBorrower {      private static final Logger log = LoggerFactory.getLogger(SandboxBorrowerImpl.class);      /** 借用中的沙箱集合: sandboxId -> 借用时间戳。 */     private final Map<String, Long> activeSandboxes = new ConcurrentHashMap<>();     private final AtomicLong idSeq = new AtomicLong(0);      @Override     public String borrow() {         String sandboxId = "sb-" + idSeq.incrementAndGet();         activeSandboxes.put(sandboxId, System.currentTimeMillis());         log.debug("借用沙箱: {}", sandboxId);         return sandboxId;     }      @Override     public void recycle(String sandboxId) {         if (sandboxId == null || sandboxId.isBlank()) {             log.warn("回收沙箱收到空 sandboxId, 跳过");             return;         }         Long removed = activeSandboxes.remove(sandboxId);         if (removed == null) {             log.warn("回收沙箱 [{}] 未找到 (可能已回收或从未借用)", sandboxId);             return;         }         log.debug("回收沙箱: {} (docker rm)", sandboxId);     }      /** 当前借用中的沙箱数量 (供测试 / 监控使用)。 */     public int activeCount() {         return activeSandboxes.size();     }      /** 判断沙箱是否处于借用状态 (供测试使用)。 */     public boolean isActive(String sandboxId) {         return sandboxId != null && activeSandboxes.containsKey(sandboxId);     } }